import { useState, useEffect, useRef, useCallback } from "react";
import { useTranslation } from "react-i18next";
import { Clock, Users, ChefHat, ChevronDown, ChevronUp, Sparkles, Globe } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { AIRecipeSuggestion, useAIRecipe } from "@/hooks/useAIRecipe";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";

interface MealDetailViewProps {
  recipes: AIRecipeSuggestion[];
}

const MealDetailView = ({ recipes }: MealDetailViewProps) => {
  const { t, i18n } = useTranslation();
  const [expandedIndex, setExpandedIndex] = useState<number>(0);
  const { generateRecipeImages, isGeneratingImages } = useAIRecipe();
  const [localImages, setLocalImages] = useState<Record<string, { url: string; source: string }>>({});
  const fetchedRef = useRef(false);

  // Auto-generate images for recipes missing them
  useEffect(() => {
    if (fetchedRef.current) return;
    const missing = recipes.filter(r => !r.image_url);
    if (missing.length === 0) return;
    fetchedRef.current = true;

    generateRecipeImages(
      missing.map(r => ({ recipe_name: r.recipe_name, recipe_name_en: r.recipe_name_en })),
      (recipeName, imageUrl, imageSource) => {
        setLocalImages(prev => ({ ...prev, [recipeName]: { url: imageUrl, source: imageSource } }));
      }
    );
  }, [recipes]);

  const getImageUrl = useCallback((recipe: AIRecipeSuggestion) => {
    if (recipe.image_url) return { url: recipe.image_url, source: recipe.image_source || "ai" };
    return localImages[recipe.recipe_name] || null;
  }, [localImages]);

  const getLocalName = (recipe: AIRecipeSuggestion) => {
    if (i18n.language === "en" && recipe.recipe_name_en) return recipe.recipe_name_en;
    if (i18n.language === "pt" && recipe.recipe_name_pt) return recipe.recipe_name_pt;
    if (i18n.language !== "zh" && recipe.recipe_name_en) return recipe.recipe_name_en;
    return recipe.recipe_name;
  };

  const getLocalSubtitle = (recipe: AIRecipeSuggestion) => {
    if (i18n.language === "en" && recipe.subtitle_en) return recipe.subtitle_en;
    if (i18n.language === "pt" && recipe.subtitle_pt) return recipe.subtitle_pt;
    if (i18n.language !== "zh" && recipe.subtitle_en) return recipe.subtitle_en;
    return recipe.subtitle;
  };

  const difficultyLabel = (d: string) => {
    switch (d) {
      case "easy": return t("recipe.difficulty.easy", "简单");
      case "medium": return t("recipe.difficulty.medium", "中等");
      case "hard": return t("recipe.difficulty.hard", "困难");
      default: return d;
    }
  };

  return (
    <div className="space-y-3">
      {recipes.map((recipe, index) => (
        <Collapsible
          key={index}
          open={expandedIndex === index}
          onOpenChange={(open) => setExpandedIndex(open ? index : -1)}
        >
          <Card className="overflow-hidden">
            {/* Recipe image */}
            {(() => {
              const img = getImageUrl(recipe);
              if (img) {
                return (
                  <div className="relative w-full aspect-[16/9] bg-muted">
                    <img
                      src={img.url}
                      alt={getLocalName(recipe)}
                      className="w-full h-full object-cover"
                      loading="lazy"
                    />
                    <div className="absolute bottom-2 right-2">
                      <span className="inline-flex items-center gap-1 text-[10px] bg-black/50 text-white px-2 py-0.5 rounded-full">
                        {img.source === "ai" ? (
                          <><Sparkles className="h-2.5 w-2.5" />{t("aiRecipe.imageSourceAI", "AI 生成")}</>
                        ) : (
                          <><Globe className="h-2.5 w-2.5" />{t("aiRecipe.imageSourceWeb", "来自网络")}</>
                        )}
                      </span>
                    </div>
                  </div>
                );
              }
              if (!recipe.image_url && isGeneratingImages) {
                return (
                  <div className="relative w-full aspect-[16/9] bg-muted overflow-hidden">
                    <Skeleton className="absolute inset-0 w-full h-full rounded-none" />
                    <div className="absolute inset-0 flex flex-col items-center justify-center gap-1.5 z-10">
                      <Sparkles className="h-5 w-5 text-primary animate-pulse" />
                      <span className="text-xs text-muted-foreground">
                        {t("aiRecipe.generatingImage", "AI 正在生成图片...")}
                      </span>
                    </div>
                  </div>
                );
              }
              return null;
            })()}
            <CollapsibleTrigger className="w-full text-left">
              <CardHeader className="pb-2 flex flex-row items-center justify-between">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <Badge variant="secondary" className="text-xs shrink-0">
                      {t("aiRecipe.dishNumber", "第 {{n}} 道", { n: index + 1 })}
                    </Badge>
                    <h4 className="font-semibold truncate">{getLocalName(recipe)}</h4>
                  </div>
                  {getLocalSubtitle(recipe) && (
                    <p className="text-xs text-muted-foreground italic mt-1">{getLocalSubtitle(recipe)}</p>
                  )}
                  <div className="flex flex-wrap gap-2 mt-2">
                    <Badge variant="outline" className="gap-1 text-xs">
                      <Clock className="h-3 w-3" />
                      {recipe.cook_time}{t("recipe.minutes", "分钟")}
                    </Badge>
                    <Badge variant="outline" className="gap-1 text-xs">
                      <ChefHat className="h-3 w-3" />
                      {difficultyLabel(recipe.difficulty)}
                    </Badge>
                  </div>
                </div>
                {expandedIndex === index ? (
                  <ChevronUp className="h-5 w-5 text-muted-foreground shrink-0 ml-2" />
                ) : (
                  <ChevronDown className="h-5 w-5 text-muted-foreground shrink-0 ml-2" />
                )}
              </CardHeader>
            </CollapsibleTrigger>

            <CollapsibleContent>
              <CardContent className="pt-0 space-y-4">
                {/* Ingredients */}
                <div>
                  <h5 className="font-semibold text-sm mb-2">{t("recipe.step.ingredients", "配料")}</h5>
                  <div className="space-y-1">
                    {recipe.ingredients.map((ing, i) => {
                      const localName = i18n.language === "en" && ing.name_en ? ing.name_en
                        : i18n.language === "pt" && ing.name_pt ? ing.name_pt
                        : ing.name;
                      return (
                        <div key={i} className="flex justify-between text-sm py-1 border-b border-dashed last:border-0">
                          <span>{localName}</span>
                          <span className="text-muted-foreground">
                            {ing.amount} {i18n.language === "en" && ing.unit_en ? ing.unit_en
                              : i18n.language === "pt" && ing.unit_pt ? ing.unit_pt
                              : ing.unit}
                          </span>
                        </div>
                      );
                    })}
                  </div>
                </div>

                {/* Steps */}
                <div>
                  <h5 className="font-semibold text-sm mb-2">{t("recipe.step.steps", "步骤")}</h5>
                  <div className="space-y-3">
                    {recipe.steps.map((step, i) => {
                      const localDesc = i18n.language === "en" && step.description_en ? step.description_en
                        : i18n.language === "pt" && step.description_pt ? step.description_pt
                        : step.description;
                      return (
                        <div key={i} className="flex gap-3">
                          <div className="w-6 h-6 rounded-full bg-primary/10 flex items-center justify-center shrink-0 mt-0.5">
                            <span className="text-xs font-bold text-primary">{step.order || i + 1}</span>
                          </div>
                          <p className="text-sm leading-relaxed">{localDesc}</p>
                        </div>
                      );
                    })}
                  </div>
                  {/* Bon appétit message */}
                  <div className="flex items-center gap-2 mt-4 pt-3 border-t border-dashed">
                    <span className="text-lg">🎉</span>
                    <p className="text-sm font-medium text-primary italic">
                      {t("recipe.bonAppetit", "祝你好口味！")}
                    </p>
                  </div>
                </div>
              </CardContent>
            </CollapsibleContent>
          </Card>
        </Collapsible>
      ))}
    </div>
  );
};

export default MealDetailView;
