import { useState, useCallback, useRef, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";

const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL;
const ANON_KEY = import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY;
const VIDEO_URL = `${SUPABASE_URL}/functions/v1/ai-recipe-video`;

const STORAGE_KEY = "xiaoxiong_video_tasks";

export type VideoTaskStatus = "idle" | "creating" | "processing" | "succeeded" | "failed";

export interface VideoTask {
  taskId: string;
  status: VideoTaskStatus;
  videoUrl: string | null;
  error: string | null;
}

export interface RecipeVideoState {
  /** All completed or in-progress tasks (max 2) */
  tasks: VideoTask[];
  /** Index of the currently selected video (in the succeeded list) */
  selectedIndex: number;
}

const MAX_ATTEMPTS = 2;

/** Load persisted tasks from localStorage */
const loadPersistedState = (): Record<string, RecipeVideoState> => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return {};
    return JSON.parse(raw);
  } catch {
    return {};
  }
};

/** Save state to localStorage (only succeeded videos) */
const persistState = (states: Record<string, RecipeVideoState>) => {
  try {
    const toSave: Record<string, RecipeVideoState> = {};
    for (const [key, state] of Object.entries(states)) {
      const succeededTasks = (state.tasks ?? []).filter(t => t.status === "succeeded" && t.videoUrl);
      if (succeededTasks.length > 0) {
        toSave[key] = { tasks: succeededTasks, selectedIndex: Math.min(state.selectedIndex, succeededTasks.length - 1) };
      }
    }
    localStorage.setItem(STORAGE_KEY, JSON.stringify(toSave));
  } catch {
    // ignore
  }
};

export const useRecipeVideo = () => {
  const [videoStates, setVideoStates] = useState<Record<string, RecipeVideoState>>(() => loadPersistedState());
  const pollTimers = useRef<Record<string, number>>({});

  useEffect(() => {
    persistState(videoStates);
  }, [videoStates]);

  const updateTaskInList = useCallback((recipeName: string, taskId: string, patch: Partial<VideoTask>) => {
    setVideoStates(prev => {
      const state = prev[recipeName];
      if (!state) return prev;
      const newTasks = (state.tasks ?? []).map(t => t.taskId === taskId ? { ...t, ...patch } : t);
      return { ...prev, [recipeName]: { ...state, tasks: newTasks } };
    });
  }, []);

  const pollTask = useCallback(async (recipeName: string, taskId: string) => {
    const timerKey = `${recipeName}_${taskId}`;
    try {
      const resp = await fetch(`${VIDEO_URL}/${taskId}`, {
        headers: { Authorization: `Bearer ${ANON_KEY}` },
      });
      if (!resp.ok) throw new Error(`Poll failed ${resp.status}`);
      const data = await resp.json();

      const status = data.status;
      if (status === "succeeded") {
        const videoUrl =
          data.content?.video_url ||
          data.content?.[0]?.url ||
          data.content?.[0]?.video_url ||
          null;
        updateTaskInList(recipeName, taskId, { status: "succeeded", videoUrl });
        // Auto-select the newest succeeded video
        setVideoStates(prev => {
          const state = prev[recipeName];
          if (!state) return prev;
          const succeededIdx = (state.tasks ?? []).filter(t => t.taskId === taskId || (t.status === "succeeded" && t.videoUrl)).length - 1;
          return { ...prev, [recipeName]: { ...state, selectedIndex: Math.max(0, succeededIdx) } };
        });
        delete pollTimers.current[timerKey];
      } else if (status === "failed") {
        updateTaskInList(recipeName, taskId, { status: "failed", error: data.error?.message || "视频生成失败" });
        delete pollTimers.current[timerKey];
      } else {
        pollTimers.current[timerKey] = window.setTimeout(() => pollTask(recipeName, taskId), 6000);
      }
    } catch (err) {
      console.error("Poll video task error:", err);
      updateTaskInList(recipeName, taskId, { status: "failed", error: "查询视频状态失败" });
      delete pollTimers.current[timerKey];
    }
  }, [updateTaskInList]);

  const generateVideo = useCallback(async (recipeName: string, imageUrl: string, prompt?: string) => {
    const existing = videoStates[recipeName];
    const totalAttempts = existing?.tasks?.length ?? 0;

    // Check if already at max attempts
    if (totalAttempts >= MAX_ATTEMPTS) return;

    // Check if there's an active task (creating/processing)
    if (existing?.tasks?.some(t => t.status === "creating" || t.status === "processing")) return;

    const newTask: VideoTask = { taskId: "", status: "creating", videoUrl: null, error: null };

    setVideoStates(prev => {
      const state = prev[recipeName] || { tasks: [], selectedIndex: 0 };
      const tasks = state.tasks ?? [];
      const keptTasks = tasks.filter(t => t.status === "succeeded");
      return {
        ...prev,
        [recipeName]: { tasks: [...keptTasks, newTask], selectedIndex: state.selectedIndex },
      };
    });

    try {
      // Get current user id
      const { data: { user } } = await supabase.auth.getUser();
      
      const resp = await fetch(VIDEO_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${ANON_KEY}`,
        },
        body: JSON.stringify({ 
          image_url: imageUrl, 
          prompt,
          user_id: user?.id || null,
          recipe_name: recipeName,
        }),
      });

      if (!resp.ok) {
        const errData = await resp.json().catch(() => ({}));
        if (resp.status === 429 && errData.error === "daily_limit_reached") {
          throw new Error(errData.message || "今日视频生成次数已达上限");
        }
        throw new Error(errData.error || `Error ${resp.status}`);
      }

      const data = await resp.json();
      const taskId = data.id;
      if (!taskId) throw new Error("No task ID returned");

      // Update the placeholder task with real taskId
      setVideoStates(prev => {
        const state = prev[recipeName];
        if (!state) return prev;
        const newTasks = (state.tasks ?? []).map(t => t.status === "creating" && !t.taskId ? { ...t, taskId, status: "processing" as const } : t);
        return { ...prev, [recipeName]: { ...state, tasks: newTasks } };
      });

      const timerKey = `${recipeName}_${taskId}`;
      pollTimers.current[timerKey] = window.setTimeout(() => pollTask(recipeName, taskId), 6000);
    } catch (err: any) {
      console.error("Generate video error:", err);
      // Mark the creating task as failed
      setVideoStates(prev => {
        const state = prev[recipeName];
        if (!state) return prev;
        const newTasks = (state.tasks ?? []).map(t => t.status === "creating" ? { ...t, status: "failed" as const, error: err.message || "创建视频任务失败" } : t);
        return { ...prev, [recipeName]: { ...state, tasks: newTasks } };
      });
    }
  }, [pollTask, videoStates]);

  const selectVideo = useCallback((recipeName: string, index: number) => {
    setVideoStates(prev => {
      const state = prev[recipeName];
      if (!state) return prev;
      return { ...prev, [recipeName]: { ...state, selectedIndex: index } };
    });
  }, []);

  // Cleanup timers on unmount
  useEffect(() => {
    return () => {
      Object.values(pollTimers.current).forEach(t => clearTimeout(t));
    };
  }, []);

  const clearTask = useCallback((recipeName: string) => {
    // Clear all timers for this recipe
    Object.keys(pollTimers.current).forEach(key => {
      if (key.startsWith(recipeName)) {
        clearTimeout(pollTimers.current[key]);
        delete pollTimers.current[key];
      }
    });
    setVideoStates(prev => {
      const next = { ...prev };
      delete next[recipeName];
      return next;
    });
  }, []);

  // Derive legacy-compatible videoTasks for backward compat
  const videoTasks: Record<string, VideoTask> = {};
  for (const [key, state] of Object.entries(videoStates)) {
    const tasks = state?.tasks ?? [];
    if (tasks.length === 0) continue;
    const activeTask = tasks.find(t => t.status === "creating" || t.status === "processing");
    const selectedSucceeded = tasks.filter(t => t.status === "succeeded")[state?.selectedIndex ?? 0];
    const failedTask = tasks.find(t => t.status === "failed");
    videoTasks[key] = activeTask || selectedSucceeded || failedTask || tasks[tasks.length - 1];
  }

  return { videoTasks, videoStates, generateVideo, selectVideo, clearTask };
};
